#include <vector>
#include <string>
#include <map>
#include <regex>

std::vector<long long> solve(std::vector<std::string> chunks, std::vector<std::string> queries) {
    // 1. Form the string s
    std::string s = "";
    for (const std::string& chunk : chunks) {
        s += chunk;
    }

    // 2. Tokenize s into valid "words" using regex.
    // A valid word structure is a sequence of letters ([a-z]+) potentially separated by single hyphens, 
    // where each hyphen is surrounded by letters.
    // The pattern [a-z]+(?:-[a-z]+)* captures maximal sequences conforming to this structure.
    std::regex word_regex("([a-z]+(?:-[a-z]+)*)");
    std::vector<std::string> wordsFound;

    auto words_begin = std::sregex_iterator(s.begin(), s.end(), word_regex);
    auto words_end = std::sregex_iterator();

    for (std::sregex_iterator i = words_begin; i != words_end; ++i) {
        std::smatch match = *i;
        wordsFound.push_back(match.str());
    }

    // 3. Count occurrences of each word
    std::map<std::string, long long> wordCounts;
    for (const std::string& word : wordsFound) {
        wordCounts[word]++;
    }

    // 4. Generate the answer array
    std::vector<long long> ans;
    for (const std::string& query : queries) {
        auto it = wordCounts.find(query);
        if (it != wordCounts.end()) {
            ans.push_back(it->second);
        } else {
            ans.push_back(0);
        }
    }

    return ans;
}

