#include <regex>

std::vector<long long> solve(std::vector<std::string> chunks, std::vector<std::string> queries) {
    // 1. Form the string s
    std::string s = "";
    for (const auto& chunk : chunks) {
        s += chunk;
    }

    // 2. Tokenize s into valid "words" using regex.
    // A word must consist of lowercase letters and hyphens, where hyphens are surrounded by letters.
    // The pattern for a valid word: one or more letters, optionally followed by zero or more sequences of (- and one or more letters).
    // [a-z]+ : Starts with at least one letter.
    // (?:-[a-z]+)* : Followed by zero or more non-capturing groups, each group being a hyphen followed by one or more letters.
    // This pattern naturally finds maximal contiguous segments adhering to the structure, and any violation (like "--" or starting/ending with '-') acts as a separator.
    std::regex wordRegex("([a-z]+(?:-[a-z]+)*)");
    std::vector<std::string> wordsFound;

    auto words_begin = std::sregex_iterator(s.begin(), s.end(), wordRegex);
    auto words_end = std::sregex_iterator();

    for (std::sregex_iterator i = words_begin; i != words_end; ++i) {
        std::smatch match = *i;
        wordsFound.push_back(match.str());
    }

    // 3. Count occurrences of each word
    std::map<std::string, long long> wordCounts;
    for (const auto& word : wordsFound) {
        wordCounts[word]++;
    }

    // 4. Generate the answer array
    std::vector<long long> ans;
    for (const auto& query : queries) {
        if (wordCounts.count(query)) {
            ans.push_back(wordCounts[query]);
        } else {
            ans.push_back(0);
        }
    }

    return ans;
}

